      "line": "                \"content\": \"name: Build & Deploy\\nrun-name: Deploy ${{ github.ref_name }} by @${{ github.actor }} to Production\\n\\nconcurrency:\\n  group: deploy-${{ github.ref }}\\n  cancel-in-progress: true\\n\\non:\\n  push:\\n    branches: [main]\\n    paths:\\n      - \\\"java/**\\\"\\n      - \\\"frontend/**\\\"\\n      - \\\"common/**\\\"\\n      - \\\"homepage/**\\\"\\n      - \\\"docker/Dockerfile.backend\\\"\\n      - \\\"docker/Dockerfile.frontend\\\"\\n      - \\\"deploy/**\\\"\\n      - \\\".github/workflows/deploy.yml\\\"\\n  workflow_dispatch:\\n\\njobs:\\n  build-and-deploy:\\n    runs-on: ubuntu-latest\\n    permissions:\\n      contents: read\\n      packages: write   # 推送 / 清理 GHCR（GitHub Container Registry） 镜像。(内置 GITHUB_TOKEN)\\n    steps:\\n      - uses: actions/checkout@v4\\n\\n      - name: Log in to GHCR\\n        uses: docker/login-action@v3\\n        with:\\n          registry: ghcr.io\\n          username: ${{ github.actor }}\\n          password: ${{ secrets.GITHUB_TOKEN }}\\n\\n      - name: Set up Builds\\n        uses: docker/setup-buildx-action@v3\\n\\n      - name: Compute image tag\\n        id: vars\\n        run: echo \\\"sha=sha-$(git rev-parse --short HEAD)\\\" >> \\\"$GITHUB_OUTPUT\\\"\\n\\n      - name: Build and push backend\\n        uses: docker/build-push-action@v6\\n        with:\\n          context: .\\n          file: docker/Dockerfile.backend\\n          push: true\\n          tags: |\\n            ghcr.io/a158coke/wotbtools-backend:${{ steps.vars.outputs.sha }}\\n            ghcr.io/a158coke/wotbtools-backend:latest\\n          cache-from: type=gha\\n          cache-to: type=gha,mode=max\\n          # 不生成 provenance/SBOM attestation: 单架构镜像无需,避免每次推送多出 index+attestation digest\\n          provenance: false\\n          sbom: false\\n\\n      - name: Build and push frontend\\n        uses: docker/build-push-action@v6\\n        with:\\n          context: .\\n          file: docker/Dockerfile.frontend\\n          push: true\\n          tags: |\\n            ghcr.io/a158coke/wotbtools-frontend:${{ steps.vars.outputs.sha }}\\n            ghcr.io/a158coke/wotbtools-frontend:latest\\n          cache-from: type=gha\\n          cache-to: type=gha,mode=max\\n          provenance: false\\n          sbom: false\\n\\n      - name: Deploy via SSH\\n        uses: appleboy/ssh-action@v1\\n        with:\\n          host: ${{ secrets.VPS_HOST }}\\n          username: ${{ secrets.VPS_USER }}\\n          port: ${{ secrets.VPS_PORT }}\\n          key: ${{ secrets.VPS_SSH_KEY }}\\n          script: |\\n            set -e\\n            mkdir -p /opt/wotb\\n            cd /opt/wotb\\n            rm -rf init-db.sql\\n            cat > init-db.sql <<'EOF'\\n            CREATE DATABASE keycloak;\\n            EOF\\n            docker rm -f wotb wotb-backend wotb-frontend 2>/dev/null || true\\n            cat > docker-compose.yml <<'EOF'\\n            services:\\n              postgres:\\n                image: postgres:18-alpine\\n                ports:\\n                  - \\\"127.0.0.1:5432:5432\\\"\\n                environment:\\n                  POSTGRES_DB: wotb\\n                  POSTGRES_USER: wotb\\n                  POSTGRES_PASSWORD: ${{ secrets.DB_PASSWORD }}\\n                volumes:\\n                  # postgres:18 把集群放在 /var/lib/postgresql/<major>/docker。现有卷数据在 18/docker,\\n                  # 因此挂载点必须用 /var/lib/postgresql(卷根),镜像默认 PGDATA 才能命中现有集群、保留数据。\\n                  - postgres_data:/var/lib/postgresql\\n                  - ./init-db.sql:/docker-entrypoint-initdb.d/init-db.sql\\n                restart: unless-stopped\\n              keycloak:\\n                image: quay.io/keycloak/keycloak:26.6.3\\n                environment:\\n                  KC_BOOTSTRAP_ADMIN_USERNAME: admin\\n                  KC_BOOTSTRAP_ADMIN_PASSWORD: ${{ secrets.KC_ADMIN_PASSWORD }}\\n                  KC_DB: postgres\\n                  KC_DB_URL: jdbc:postgresql://postgres:5432/keycloak\\n                  KC_DB_USERNAME: wotb\\n                  KC_DB_PASSWORD: ${{ secrets.DB_PASSWORD }}\\n                volumes:\\n                  # QQ 社交登录 provider(start 时自动 build 加载)\\n                  - ./keycloak-qq.jar:/opt/keycloak/providers/keycloak-qq.jar\\n                command: start --hostname=auth.wotbtools.com --hostname-strict=false --http-enabled=true --http-port=8080 --proxy-headers=xforwarded\\n                ports:\\n                  - \\\"127.0.0.1:8080:8080\\\"\\n                depends_on:\\n                  - postgres\\n                restart: unless-stopped\\n              wotb-backend:\\n                image: ghcr.io/a158coke/wotbtools-backend:${{ steps.vars.outputs.sha }}\\n                depends_on:\\n                  - postgres\\n                  - keycloak\\n                environment:\\n                  POSTGRES_HOST: postgres\\n                  POSTGRES_PASSWORD: ${{ secrets.DB_PASSWORD }}\\n                  KEYCLOAK_ISSUER_URI: https://auth.wotbtools.com/realms/wotbtools\\n                restart: unless-stopped\\n              wotb-frontend:\\n                image: ghcr.io/a158coke/wotbtools-frontend:${{ steps.vars.outputs.sha }}\\n                ports:\\n                  - \\\"127.0.0.1:8088:80\\\"\\n                depends_on:\\n                  - wotb-backend\\n                  - keycloak\\n                restart: unless-stopped\\n            volumes:\\n              postgres_data:\\n            EOF\\n            # QQ 社交登录 provider JAR(挂载进 keycloak); 必须在 up 之前存在,否则 docker 会把它当目录\\n            curl -fSL -o keycloak-qq.jar https://github.com/trashblazer/keycloak-social-provider-china/releases/download/v1.0.0/keycloak-social-provider-china-1.0.0.jar\\n            docker compose pull\\n            docker compose up -d --remove-orphans\\n            # 确保 keycloak 数据库存在（init-db.sql 仅在首次初始化执行）\\n            docker compose exec -T postgres psql -U wotb -d wotb -c \\\"CREATE DATABASE keycloak;\\\" 2>/dev/null || true\\n            # 清理磁盘：旧镜像 + 构建缓存\\n            docker image prune -af\\n            docker builder prune -af\\n            # 健康检查：等待所有容器无 restarting 状态，最多 60 秒\\n            for i in $(seq 1 30); do\\n              if docker compose ps | grep -qE \\\"Restarting|Exited|unhealthy\\\"; then\\n                sleep 2\\n              else\\n                break\\n              fi\\n            done\\n            if docker compose ps | grep -qE \\\"Restarting|Exited|unhealthy\\\"; then\\n              echo \\\"ERROR: Containers not healthy!\\\"\\n              docker compose ps\\n              docker compose logs --tail 50\\n              exit 1\\n            fi\\n\\n  # 部署成功后清理 GHCR: 每个镜像只保留最近 5 个版本,删更老的(含无 tag)。\\n  # 官方 Action + 内置 GITHUB_TOKEN,独立 job: 清理失败也不影响已成功的部署。\\n  cleanup-ghcr:\\n    needs: build-and-deploy\\n    runs-on: ubuntu-latest\\n    permissions:\\n      packages: write\\n    steps:\\n      - name: Prune backend versions (keep 5)\\n        uses: actions/delete-package-versions@v5\\n        with:\\n          package-name: wotbtools-backend\\n          package-type: container\\n          min-versions-to-keep: 5\\n      - name: Prune frontend versions (keep 5)\\n        uses: actions/delete-package-versions@v5\\n        with:\\n          package-name: wotbtools-frontend\\n          package-type: container\\n          min-versions-to-keep: 5\\n\"",
