package com.wotbtools.keycloak.juheqq;

import org.keycloak.models.IdentityProviderModel;

public final class JuheQqIdentityProviderConfig extends IdentityProviderModel {

    public static final String CONFIG_APPID = "appid";
    public static final String CONFIG_APP_KEY = "appkey";
    public static final String CONFIG_LOGIN_BASE_URL = "loginBaseUrl";
    public static final String DEFAULT_LOGIN_BASE_URL = "https://open.juhedenglu.cn/connect.php";

    public JuheQqIdentityProviderConfig() {
    }

    public JuheQqIdentityProviderConfig(final IdentityProviderModel model) {
        super(model);
    }

    public String getAppid() {
        return getConfig().get(CONFIG_APPID);
    }

    public String getAppkey() {
        return getConfig().get(CONFIG_APP_KEY);
    }

    public String getLoginBaseUrl() {
        final String url = getConfig().get(CONFIG_LOGIN_BASE_URL);
        return (url != null && !url.isBlank()) ? url : DEFAULT_LOGIN_BASE_URL;
    }
}

package com.wotbtools.keycloak.juheqq;

import org.keycloak.broker.provider.AbstractIdentityProviderFactory;
import org.keycloak.models.IdentityProviderModel;
import org.keycloak.models.KeycloakSession;
import org.keycloak.provider.ProviderConfigProperty;

import java.util.ArrayList;
import java.util.List;

public final class JuheQqIdentityProviderFactory
        extends AbstractIdentityProviderFactory<JuheQqIdentityProvider> {

    public static final String PROVIDER_ID = "juhe-qq";

    @Override
    public String getId() {
        return PROVIDER_ID;
    }

    @Override
    public String getName() {
        return "Juhe QQ";
    }

    @Override
    public JuheQqIdentityProvider create(final KeycloakSession session,
                                         final IdentityProviderModel model) {
        return new JuheQqIdentityProvider(session, new JuheQqIdentityProviderConfig(model));
    }

    @Override
    public List<ProviderConfigProperty> getConfigProperties() {
        final List<ProviderConfigProperty> props = new ArrayList<>();

        final ProviderConfigProperty appid = new ProviderConfigProperty();
        appid.setName(JuheQqIdentityProviderConfig.CONFIG_APPID);
        appid.setLabel("APPID");
        appid.setHelpText("聚合登录平台分配的 APPID");
        appid.setType(ProviderConfigProperty.STRING_TYPE);
        props.add(appid);

        final ProviderConfigProperty appkey = new ProviderConfigProperty();
        appkey.setName(JuheQqIdentityProviderConfig.CONFIG_APPKEY);
        appkey.setLabel("APPKEY");
        appkey.setHelpText("聚合登录平台分配的 APPKEY（加密存储，不打印日志）");
        appkey.setType(ProviderConfigProperty.STRING_TYPE);
        appkey.setSecret(true);
        props.add(appkey);

        final ProviderConfigProperty loginBaseUrl = new ProviderConfigProperty();
        loginBaseUrl.setName(JuheQqIdentityProviderConfig.CONFIG_LOGIN_BASE_URL);
        loginBaseUrl.setLabel("Login Base URL");
        loginBaseUrl.setHelpText("聚合登录平台接口地址");
        loginBaseUrl.setType(ProviderConfigProperty.STRING_TYPE);
        loginBaseUrl.setDefaultValue(JuheQqIdentityProviderConfig.DEFAULT_LOGIN_BASE_URL);
        props.add(loginBaseUrl);

        return props;
    }
}

import Keycloak from 'keycloak-js'
import { computed, ref } from 'vue'

let keycloak = null
let initPromise = null

const initialized = ref(false)
const authenticated = ref(false)
const tokenParsed = ref(null)
const initError = ref(null)

function ensureKeycloak() {
  if (!keycloak) {
    keycloak = new Keycloak({
      url: 'https://auth.wotbtools.com',
      realm: 'wotbtools',
      clientId: 'wotbtools-web',
    })
  }
  return keycloak
}

function profileRedirectUri() {
  const url = new URL(window.location.origin + window.location.pathname)
  url.searchParams.set('view', 'profile')
  return url.toString()
}

async function initAuth() {
  const kc = ensureKeycloak()

  if (!initPromise) {
    initPromise = kc.init({
      onLoad: 'check-sso',
      pkceMethod: 'S256',
      checkLoginIframe: false,
    }).then(isLoggedIn => {
      authenticated.value = Boolean(isLoggedIn && kc.authenticated)
      tokenParsed.value = kc.tokenParsed || null
      initialized.value = true
      initError.value = null
      return authenticated.value
    }).catch(err => {
      console.error('Keycloak init failed', err)
      authenticated.value = false
      tokenParsed.value = null
      initialized.value = true
      initError.value = err
      return false
    })
  }

  return initPromise
}

async function login() {
  const kc = ensureKeycloak()
  await initAuth()
  return kc.login({ redirectUri: profileRedirectUri(), idpHint: 'juhe-qq' })
}

async function logout() {
  const kc = ensureKeycloak()
  return kc.logout({ redirectUri: window.location.origin + window.location.pathname })
}

function isAuthenticated() {
  return authenticated.value
}

function userName() {
  return tokenParsed.value?.preferred_username
    || tokenParsed.value?.name
    || tokenParsed.value?.email
    || ''
}

function token() {
  return keycloak?.token || ''
}

export function useAuth() {
  return {
    keycloak: ensureKeycloak(),
    initAuth,
    initPromise: initAuth(),
    login,
    logout,
    isAuthenticated,
    userName,
    token,
    initialized,
    authenticated,
    tokenParsed,
    initError,
    displayName: computed(() => userName()),
  }
}

